/**
 * Generated by `createservice acquiring.RegisterMultiPaymentService`
 */
const Big = require('big.js')

const { GQLError } = require('@open-condo/keystone/errors')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema } = require('@open-condo/keystone/schema')

const access = require('@condo/domains/acquiring/access/RegisterMultiPaymentService')
const { DEFAULT_MULTIPAYMENT_SERVICE_CATEGORY } = require('@condo/domains/acquiring/constants/payment')
const { REQUEST_MODE } = require('@condo/domains/acquiring/constants/registerMultiPaymentDomain')
const { REGISTER_MULTI_PAYMENT_ERRORS: ERRORS } = require('@condo/domains/acquiring/constants/registerMultiPaymentErrors')
const { MultiPayment, Payment } = require('@condo/domains/acquiring/utils/serverSchema')
const {
    buildInvoicePaymentInputs,
    buildReceiptPaymentInputs,
    buildOutputUrls,
} = require('@condo/domains/acquiring/utils/serverSchema/registerMultiPayment/builders')
const {
    calculateTotals,
    detectRequestMode,
} = require('@condo/domains/acquiring/utils/serverSchema/registerMultiPayment/helpers')
const {
    loadAcquiringIntegration,
    loadBillingAccountsByIds,
    loadBillingContextsByIds,
    loadBillingContextsByOrganizationIds,
    loadBillingIntegrationsByIds,
    loadInvoicesByIds,
    loadReceiptsByIds,
    loadResidentsByIds,
    loadServiceConsumersByIds,
    loadAcquiringContextsForConsumers,
    loadAcquiringContextsForInvoices,
} = require('@condo/domains/acquiring/utils/serverSchema/registerMultiPayment/loaders')
const {
    validateAcquiringIntegrationExists,
    validateAllPaymentAmountsPositive,
    validateBillingIntegrationsSupportedByAcquiring,
    validateCanGroupReceiptsIfNeeded,
    validateCurrencyConsistency,
    validateGroupedReceiptsHaveReceipts,
    validateInvoiceAcquiringContextsFinished,
    validateInvoicesArePublished,
    validateInvoicesBelongToCurrentUser,
    validateNoDuplicateInvoices,
    validateNoDuplicateReceipts,
    validateNoDuplicateServiceConsumers,
    validateNoRecurrentPaymentContextForInvoiceMode,
    validateReceiptBelongsToServiceConsumer,
    validateReceiptsHavePositiveToPay,
    validateSingleAcquiringIntegration,
    validateServiceConsumersBelongToCurrentUser,
    validateTotalAmountWithinAcquiringLimits,
    validateValidAmountDistribution,
    validateRecurrentPaymentContext,
} = require('@condo/domains/acquiring/utils/serverSchema/registerMultiPayment/validators')
const { DEFAULT_INVOICE_CURRENCY_CODE } = require('@condo/domains/marketplace/constants')

const RegisterMultiPaymentService = new GQLCustomSchema('RegisterMultiPaymentService', {
    types: [
        {
            access: true,
            type: 'input RegisterMultiPaymentReceiptAmountInput { receipt: BillingReceiptWhereUniqueInput!, amount: String! }',
        },
        {
            access: true,
            type: 'input RegisterMultiPaymentServiceConsumerInput { serviceConsumer: ServiceConsumerWhereUniqueInput!, receipts: [BillingReceiptWhereUniqueInput!]!, amountDistribution: [RegisterMultiPaymentReceiptAmountInput!] }',
        },
        {
            access: true,
            type: 'input RegisterMultiPaymentInput { dv: Int!, sender: SenderFieldInput!, groupedReceipts: [RegisterMultiPaymentServiceConsumerInput!], recurrentPaymentContext: RecurrentPaymentContextWhereUniqueInput, invoices: [InvoiceWhereUniqueInput!] }',
        },
        {
            access: true,
            type: 'type RegisterMultiPaymentOutput { dv: Int!, multiPaymentId: String!, webViewUrl: String!, feeCalculationUrl: String!, directPaymentUrl: String!, getCardTokensUrl: String! }',
        },
    ],

    mutations: [
        {
            access: access.canRegisterMultiPayment,
            schema: 'registerMultiPayment(data: RegisterMultiPaymentInput!): RegisterMultiPaymentOutput',
            resolver: async (parent, args, context) => {
                const { data } = args
                const { sender, recurrentPaymentContext } = data
                const groupedReceipts = data?.groupedReceipts || []
                const invoices = data?.invoices || []

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                const mode = detectRequestMode(groupedReceipts, invoices, context)

                if (mode === REQUEST_MODE.RECEIPTS) {
                    validateGroupedReceiptsHaveReceipts(groupedReceipts, context)
                    validateNoDuplicateServiceConsumers(groupedReceipts, context)
                    validateNoDuplicateReceipts(groupedReceipts, context)
                    validateValidAmountDistribution(groupedReceipts, context)
                } else if (mode === REQUEST_MODE.INVOICES) {
                    validateNoDuplicateInvoices(invoices, context)
                    validateNoRecurrentPaymentContextForInvoiceMode(recurrentPaymentContext, context)
                } else {
                    throw new GQLError(ERRORS.INVALID_REQUEST_MODE, context)
                }

                let consumers, consumersByIds, receipts, receiptsByIds, foundInvoices
                let billingContexts, billingIntegrations, billingIntegrationCurrencyCode
                let billingAccountsById, billingContextsByOrganizationId
                let acquiringContexts, acquiringContextsByConsumerId
                let residentsById

                if (mode === REQUEST_MODE.RECEIPTS) {
                    const consumersIds = groupedReceipts.map(group => group.serviceConsumer.id)
                    const receiptsIds = groupedReceipts.flatMap(group => group.receipts).map(receiptInfo => receiptInfo.id)
                    const hasDistribution = groupedReceipts.some(group => group.amountDistribution && group.amountDistribution.length > 0)

                    const loadedConsumers = await loadServiceConsumersByIds(consumersIds, context)
                    consumers = loadedConsumers.list
                    consumersByIds = loadedConsumers.byId
                    const loadedResidents = await loadResidentsByIds(consumers.map(({ resident }) => resident))
                    residentsById = loadedResidents.byId

                    const loadedReceipts = await loadReceiptsByIds(receiptsIds, context)
                    receipts = loadedReceipts.list
                    receiptsByIds = loadedReceipts.byId

                    const loadedAccounts = await loadBillingAccountsByIds(receipts.map(({ account }) => account))
                    billingAccountsById = loadedAccounts.byId
                    
                    validateReceiptsHavePositiveToPay(receipts, hasDistribution, context)

                    const loadedBillingContexts = await loadBillingContextsByIds(receipts.map(({ context }) => context))
                    billingContexts = loadedBillingContexts.list
                    billingContextsByOrganizationId = await loadBillingContextsByOrganizationIds(consumers.map(({ organization }) => organization))

                    const loadedBillingIntegrations = await loadBillingIntegrationsByIds(billingContexts.map(({ integration }) => integration), context)
                    billingIntegrations = loadedBillingIntegrations.list
                    billingIntegrationCurrencyCode = billingIntegrations[0]?.currencyCode

                    const acquiringContextsForConsumers = await loadAcquiringContextsForConsumers(consumers, context)
                    acquiringContexts = acquiringContextsForConsumers.list
                    acquiringContextsByConsumerId = acquiringContextsForConsumers.byConsumerId
                } else if (mode === REQUEST_MODE.INVOICES) {
                    const loadedInvoices = await loadInvoicesByIds(invoices.map(({ id }) => id), context)
                    foundInvoices = loadedInvoices.list

                    const acquiringContextsForInvoices = await loadAcquiringContextsForInvoices(foundInvoices, context)
                    acquiringContexts = acquiringContextsForInvoices.list
                } else {
                    throw new GQLError(ERRORS.INVALID_REQUEST_MODE, context)
                }

                validateSingleAcquiringIntegration(acquiringContexts, context)

                const [acquiringIntegrationId] = Array.from(new Set(acquiringContexts.map(item => item.integration)))
                const acquiringIntegration = await loadAcquiringIntegration(acquiringIntegrationId, context)
                validateAcquiringIntegrationExists(acquiringIntegration, context)

                if (mode === REQUEST_MODE.RECEIPTS) {
                    validateServiceConsumersBelongToCurrentUser(consumers, residentsById, context.authedItem.id, context)
                }

                if (mode === REQUEST_MODE.RECEIPTS) {
                    validateCanGroupReceiptsIfNeeded(receipts.length, acquiringIntegration, context)
                    validateBillingIntegrationsSupportedByAcquiring(billingIntegrations, acquiringIntegration.supportedBillingIntegrationsGroup, context)
                    validateCurrencyConsistency(billingIntegrations, context)
                    validateReceiptBelongsToServiceConsumer(
                        groupedReceipts,
                        consumersByIds,
                        receiptsByIds,
                        billingAccountsById,
                        billingContextsByOrganizationId,
                        context,
                    )
                } else if (mode === REQUEST_MODE.INVOICES) {
                    validateInvoicesArePublished(foundInvoices, context)
                    validateInvoicesBelongToCurrentUser(foundInvoices, context.authedItem.id, context)
                    validateInvoiceAcquiringContextsFinished(acquiringContexts, context)
                } else {
                    throw new GQLError(ERRORS.INVALID_REQUEST_MODE, context)
                }

                if (recurrentPaymentContext){
                    await validateRecurrentPaymentContext(recurrentPaymentContext.id, context)
                }

                const paymentCreateInputs = mode === REQUEST_MODE.RECEIPTS
                    ? await buildReceiptPaymentInputs({
                        groupedReceipts,
                        consumersByIds,
                        receiptsByIds,
                        acquiringContextsByConsumerId,
                        billingIntegrationCurrencyCode,
                        sender,
                        context,
                    })
                    : await buildInvoicePaymentInputs({
                        foundInvoices,
                        acquiringContext: acquiringContexts[0],
                        acquiringIntegration,
                        sender,
                        context,
                    })

                validateAllPaymentAmountsPositive(paymentCreateInputs, context)

                const totalAmount = calculateTotals(paymentCreateInputs)
                const amountToPay = Big(totalAmount.amountWithoutExplicitFee)
                    .add(Big(totalAmount.explicitServiceCharge))
                    .add(Big(totalAmount.explicitFee))

                validateTotalAmountWithinAcquiringLimits(amountToPay, acquiringIntegration, context)

                const payments = await Promise.all(paymentCreateInputs.map((paymentInput) => Payment.create(context, paymentInput)))
                const currencyCode = billingIntegrationCurrencyCode || DEFAULT_INVOICE_CURRENCY_CODE
                const paymentIds = payments.map(({ id }) => ({ id }))
                const recurrentPaymentContextField = recurrentPaymentContext ? {
                    recurrentPaymentContext: { connect: { id: recurrentPaymentContext.id } },
                } : {}

                const multiPayment = await MultiPayment.create(context, {
                    dv: 1,
                    sender,
                    ...Object.fromEntries(Object.entries(totalAmount).map(([key, value]) => ([key, value.toFixed(2)]))),
                    currencyCode,
                    user: { connect: { id: context.authedItem.id } },
                    integration: { connect: { id: acquiringIntegration.id } },
                    payments: { connect: paymentIds },
                    serviceCategory: DEFAULT_MULTIPAYMENT_SERVICE_CATEGORY,
                    ...recurrentPaymentContextField,
                })

                return {
                    dv: 1,
                    multiPaymentId: multiPayment.id,
                    ...buildOutputUrls(acquiringIntegration.hostUrl, multiPayment.id, context.authedItem.id),
                }
            },
        },
    ],
})

module.exports = {
    RegisterMultiPaymentService,
}
